INSERT INTO RepliesByType (category, webhook_action, reply_text) VALUES
('Report Missed Recycling Collection', false, 'For missed recycling collection, contact: Central Virginia Waste Management Authority at 804-340-0900.'),
('Report Missed Trash Collection', false, 'To report missed trash, call 804-646-1798.'),
('How To Report A Gas Leak', false, 'All gas leaks are handled as emergencies. If you think you smell a natural gas leak, immediately call (804) 646-4646. If there is immediate danger, please call 911.'),
('Report Water Leak Or Missing Utility Cover', false, 'Water leaks and missing utility covers are handled as emergencies and should be reported immediately. To ensure response within 12 hours please call 804-646-4646 and press 1. This number is available 24 hours a day.'),
('How To Report On-Street Parking Violation', false, 'During weekdays, call (804) 649-3025. After hours or weekends, call the non-emergency police line at (804) 646-5100.'),
('On Street Parking Violations', false, 'During weekdays, call (804) 649-3025. After hours or weekends, call the non-emergency police line at (804) 646-5100.'),
